#!/usr/bin/env -S npx ts-node -r tsconfig-paths/register
/**
 * Example: Create and wait for a Databricks cluster
 *
 * This example demonstrates:
 * - Creating a cluster with basic configuration
 * - Using the waiter pattern to wait for cluster readiness
 * - Progress callbacks during long-running operations
 * - Cleaning up resources
 *
 * Prerequisites:
 * - DATABRICKS_HOST environment variable
 * - Valid authentication (PAT, OAuth M2M, or other)
 *
 * Usage:
 *   npx ts-node examples/workspace/clusters/create-cluster.ts
 */

import {WorkspaceClient, Time, TimeUnits} from "@databricks/sdk-experimental";

async function main() {
    const client = new WorkspaceClient({});

    // Generate unique name for cluster
    const clusterName = `sdk-example-${Date.now()}`;

    console.log(`Creating cluster: ${clusterName}`);

    try {
        // Create cluster and get waiter
        const waiter = await client.clusters.create({
            cluster_name: clusterName,
            spark_version: await client.clusters.selectSparkVersion({
                latest: true,
            }),
            node_type_id: await client.clusters.selectNodeType({
                minMemoryGb: 8,
                minCores: 2,
            }),
            num_workers: 1,
            autotermination_minutes: 15,
        });

        // Wait for cluster to be ready with progress updates
        const cluster = await waiter.wait({
            timeout: new Time(15, TimeUnits.minutes),
            onProgress: async (c) => {
                console.log(
                    `  Cluster state: ${c.state}${c.state_message ? " - " + c.state_message : ""}`
                );
            },
        });

        console.log(`✓ Cluster created successfully!`);
        console.log(`  Cluster ID: ${cluster.cluster_id}`);
        console.log(
            `  Cluster URL: ${client.config.host}#/setting/clusters/${cluster.cluster_id}/configuration`
        );

        // Cleanup: Delete the cluster
        console.log(`\nCleaning up: deleting cluster ${cluster.cluster_id}`);
        await client.clusters.permanentDelete({
            cluster_id: cluster.cluster_id!,
        });
        console.log(`✓ Cluster deleted`);
    } catch (error) {
        console.error(`✗ Error:`, error);
        process.exit(1);
    }
}

main();
